const body = $input.first().json;
const action = body.action;
const BASE = 'http://localhost:5000';
const SECRET = 'aurvex-ax-secret';
const endpoints = {
  pause:      { method: 'POST', url: `${BASE}/n8n/pause` },
  resume:     { method: 'POST', url: `${BASE}/n8n/resume` },
  status:     { method: 'GET',  url: `${BASE}/n8n/status` },
  ai_trigger: { method: 'POST', url: `${BASE}/n8n/ai_trigger` },
  finish:     { method: 'POST', url: `${BASE}/n8n/finish` },
};
const ep = endpoints[action];
if (!ep) return [{ json: { error: 'Bilinmeyen: ' + action } }];
return [{ json: { url: ep.url, method: ep.method, secret: SECRET } }];
